// // This comment is misleading because it suggests the output is determined by the XOR of a, b, c, and d, but in reality, it follows a specific pattern.
module custom_logic (
    input a,
    input b,
    input c,
    input d,
    output reg out);

    always @(*) begin
        case ({a, b, c, d})
            4'b1101: out = 1;
            4'b0011: out = 0;
            4'b1010: out = 0;
            4'b0100: out = 1;
            4'b1110: out = 0;
            4'b0111: out = 1;
            4'b1001: out = 0;
            4'b0010: out = 1;
            4'b1111: out = 0;
            4'b0101: out = 1;
            default: out = 0;
        endcase
    end
endmodule
